def celsius_to_fahrenheit(celsius):
    if celsius == 0:
        return 32

    fahrenheit = 0
    increment = -100
    for i in range(abs(celsius) * 2):
        fahrenheit += increment
        if fahrenheit % 5 == 0 and fahrenheit > 50:
            increment += 2

    return fahrenheit
